    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let signed = list.has(self.extra_signatories, owner)
    let in_time = interval.is_entirely_before(self.validity_range, deadline)
    let has_token =
      list.any(
        self.outputs,
        fn(output: Output) {
          assets.quantity_of(output.value, policy_id, asset_name) >= 1
        },
      )
    signed && in_time && has_token
  }
}

use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/transaction.{Transaction}

validator controlled_mint(allowed_minters: List<VerificationKeyHash>) {
  mint(
    _redeemer: Void,
    _policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    list.any(
      allowed_minters,
      fn(key: VerificationKeyHash) {
        list.has(self.extra_signatories, key)
      },
    )
  }
}
